import { NextRequest, NextResponse } from "next/server";
import { z } from "zod";
import { stripe, isStripeConfigured } from "@/lib/stripe";
import { supabase } from "@/lib/supabase";
import * as orderService from "@/lib/services/orderService";

export const dynamic = 'force-dynamic';

const paymentIntentSchema = z.object({
    customer: z.object({
        name: z.string().min(1, "Customer name is required"),
        email: z.string().email(),
        phone: z.string().optional(),
        address: z.string().optional(),
        city: z.string().optional(),
        country: z.string().optional(),
        notes: z.string().optional(),
    }),
    items: z.array(z.object({
        id: z.union([z.string(), z.number()]),
        name: z.string(),
        price: z.number(),
        quantity: z.number().int().min(1),
        image: z.string().optional(),
        variant: z.string().optional(),
    })).min(1, "At least one item is required"),
    total: z.number().min(0.5),
    dummyPayment: z.boolean().optional(),
});

export async function POST(req: NextRequest){
    try {
        const body = await req.json();
        const data = paymentIntentSchema.parse(body);

        if (!data.dummyPayment && (!isStripeConfigured() || !stripe)) {
            return NextResponse.json({
                success: false,
                message: 'Stripe is not configured. Please add STRIPE_SECRET_KEY to your environment variables.',
            }, { status: 503, statusText: "Stripe is not configured" });
        }

        // Step 0: Pre-flight Stock Check
        for (const item of data.items) {
            const productId = String(item.id);
            const { data: productData, error: productError } = await supabase
                .from('products')
                .select('stock, name')
                .eq('id', productId)
                .single();

            if (productError || !productData) {
                return NextResponse.json({
                    success: false,
                    message: `Product ${item.name} not found.`,
                }, { status: 400 });
            }

            if (productData.stock < item.quantity) {
                return NextResponse.json({
                    success: false,
                    message: `Insufficient stock for ${productData.name}. Only ${productData.stock} available.`,
                }, { status: 400 });
            }
        }

        // Step 1: Find or create customer
        let customerId: string ;
        const { data: existing} = await supabase.from('customers').select('id').eq('email', data.customer.email).limit(1);

        if(existing && existing.length >0 ){
            customerId = existing[0].id;
        }
        else{
            const {data : created, error: createError} = await supabase
            .from('customers')
            .insert([{
                id : crypto.randomUUID(),
                name: data.customer.name,
                email: data.customer.email,
                phone: data.customer.phone || null,
                address: data.customer.address || null,
                city: data.customer.city || null,
                country: data.customer.country || null,
                createdAt: new Date().toISOString(),
                updatedAt: new Date().toISOString(),
            }])
            .select('id')
            .single();

            if (createError || !created){
                console.error('Cusotmer creation error:', createError);
                return NextResponse.json({
                    success: false,
                    message: 'Failed to create customer',
                },{status: 500, statusText: "Failed to create customer"});
            }

            customerId = created.id;
        }
            //step2: create pending order in database
            const isDummy = !!data.dummyPayment;
            const order = await orderService.create({
                customer_id: customerId,
                status: isDummy ? 'PROCESSING' : 'PENDING',
                total: data.total,
                subtotal: data.total,
                shipping: 0,
                notes: data.customer.notes || null,
                payment_status: isDummy ? 'paid' : 'unpaid',
                items: data.items.map((item) => ({
                    product_id: String(item.id),
                    quantity: item.quantity,
                    price: item.price,
                    name: item.name,
                    variant: item.variant,
                })),
            });

            // Step 2.5: Stock Deduction
            for (const item of data.items) {
                const productId = String(item.id);
                const { data: currentProduct } = await supabase.from('products').select('stock').eq('id', productId).single();
                if (currentProduct) {
                    await supabase.from('products').update({ stock: Math.max(0, currentProduct.stock - item.quantity) }).eq('id', productId);
                }
            }

            if (isDummy) {
                return NextResponse.json({
                    success: true,
                    dummyMode: true,
                    orderId: order.id,
                    message: "Test order placed successfully",
                });
            }

            // Step 3: Create Stripe Payment Intent
            if (!stripe) {
                throw new Error("Stripe is not configured");
            }

            const paymentIntent = await stripe.paymentIntents.create({
                amount: Math.round(data.total * 100), // Convert to cents
                currency: 'usd',
                automatic_payment_methods: {enabled: true},
                receipt_email: data.customer.email,
                metadata: {
                    order_id: order.id,
                    customer_id: customerId,
                    customer_email: data.customer.email,
                },
            });

            //step 4: Update order with payment intent id
            await supabase
            .from('orders')
            .update({ stripe_payment_intent_id: paymentIntent.id })
            .eq('id', order.id);

            return NextResponse.json({
                success: true,
                clientSecret: paymentIntent.client_secret,
                orderId: order.id,
                paymentIntentId: paymentIntent.id,
            });
    }
    catch (error: any) {
        console.error('Payment Intent creation error:', error);

        if(error.name === 'ZodError'){
            return NextResponse.json({
                success: false,
                message: 'Invalid request data',
                errors: error.issues,
            }, {status: 400});
        }

        return NextResponse.json({
            success: false,
            message: error.message || 'Failed to create payment intent',
        }, {status: 500});
    }
}

import { NextResponse } from 'next/server';
import { supabase } from '@/lib/supabase';

export const dynamic = 'force-dynamic';

export async function GET(request: Request) {
    const { searchParams } = new URL(request.url);
    const code = searchParams.get('code');

    if (!code) {
        return NextResponse.json({ success: false, message: 'Coupon code is required' }, { status: 400 });
    }

    try {
        const { data, error } = await supabase
            .from('coupons')
            .select('*')
            .eq('code', code.toUpperCase())
            .eq('is_active', true)
            .single();

        if (error || !data) {
            return NextResponse.json({ success: false, message: 'Invalid or expired coupon code' }, { status: 404 });
        }

        // Check expiry if set
        if (data.expiry_date && new Date(data.expiry_date) < new Date()) {
            return NextResponse.json({ success: false, message: 'This coupon has expired' }, { status: 400 });
        }

        return NextResponse.json({
            success: true,
            data: {
                id: data.id,
                code: data.code,
                discountType: data.discount_type,
                value: parseFloat(data.value),
                minOrderAmount: parseFloat(data.min_order_amount || 0)
            }
        });
    } catch (error: any) {
        return NextResponse.json({ success: false, message: error.message }, { status: 500 });
    }
}

import { NextResponse } from 'next/server';
import { supabase } from '@/lib/supabase';
import { auditLog } from '@/lib/services/auditService';


export const dynamic = 'force-dynamic';

const BUCKET = 'product-images';

export async function GET() {
    // 1. Get files from Storage
    const { data: storageData, error: storageError } = await supabase.storage.from(BUCKET).list('', {
        limit: 100,
        sortBy: { column: 'created_at', order: 'desc' }
    });

    const storageFiles = (storageData || []).filter(f => f.name !== '.emptyFolderPlaceholder').map(f => ({
        name: f.name,
        url: supabase.storage.from(BUCKET).getPublicUrl(f.name).data.publicUrl,
        size: f.metadata?.size || 0,
        created_at: f.created_at,
        source: 'storage'
    }));

    // 2. Get files from Database
    const { data: dbData, error: dbError } = await supabase
        .from('media_files')
        .select('*')
        .order('created_at', { ascending: false })
        .limit(100);

    const dbFiles = (dbData || []).map(f => ({
        name: f.filename,
        url: f.url,
        size: f.size || 0,
        created_at: f.created_at,
        source: 'database'
    }));

    // Combine and remove duplicates (by URL)
    const combined = [...storageFiles];
    const seenUrls = new Set(storageFiles.map(f => f.url));

    for (const f of dbFiles) {
        if (!seenUrls.has(f.url)) {
            combined.push(f);
            seenUrls.add(f.url);
        }
    }

    return NextResponse.json({ success: true, data: combined });
}

export async function POST(request: Request) {
    const formData = await request.formData();
    const file = formData.get('file') as File;
    if (!file) return NextResponse.json({ success: false, message: 'No file provided' }, { status: 400 });

    const ext = file.name.split('.').pop();
    const filename = `${Date.now()}-${Math.random().toString(36).slice(2)}.${ext}`;

    const { error } = await supabase.storage.from(BUCKET).upload(filename, file, {
        contentType: file.type,
        upsert: false
    });

    if (error) return NextResponse.json({ success: false, message: error.message }, { status: 500 });

    const url = supabase.storage.from(BUCKET).getPublicUrl(filename).data.publicUrl;
    await auditLog('media', filename, 'CREATE', { url: { from: null, to: url } });
    return NextResponse.json({ success: true, data: { name: filename, url } });
}

export async function DELETE(request: Request) {
    const { searchParams } = new URL(request.url);
    const name = searchParams.get('name');
    if (!name) return NextResponse.json({ success: false, message: 'File name required' }, { status: 400 });

    const { error } = await supabase.storage.from(BUCKET).remove([name]);
    if (error) return NextResponse.json({ success: false, message: error.message }, { status: 500 });
    await auditLog('media', name, 'DELETE');
    return NextResponse.json({ success: true });
}

