import { NextRequest, NextResponse } from 'next/server';
import { supabase } from '../../../../lib/supabase';

export const dynamic = 'force-dynamic';

/**
 * @route   GET /api/products/validate?ids=uuid1,uuid2,...
 * @desc    Check which products from a given list are still available
 *          (isActive=true and stock > 0).
 *
 * Used by CartContext on open to strip unavailable items from localStorage.
 *
 * Response:
 *   {
 *     success: true,
 *     data: [
 *       { id, isActive, stock, name }   // one entry per requested id
 *     ],
 *     unavailableIds: string[]          // convenience: ids that are gone/inactive
 *   }
 */
export async function GET(req: NextRequest) {
    const { searchParams } = new URL(req.url);
    const raw = searchParams.get('ids') ?? '';

    if (!raw.trim()) {
        return NextResponse.json({ success: true, data: [], unavailableIds: [] });
    }

    const ids = raw.split(',').map(id => id.trim()).filter(Boolean);

    if (ids.length === 0) {
        return NextResponse.json({ success: true, data: [], unavailableIds: [] });
    }

    const { data, error } = await supabase
        .from('products')
        .select('id, name, "isActive", stock')
        .in('id', ids);

    if (error) {
        console.error('[validate] DB error:', error);
        // On error, return all ids as available so we don't falsely clear carts
        return NextResponse.json({ success: true, data: [], unavailableIds: [] });
    }

    // Build a set of found IDs
    const foundIds = new Set((data ?? []).map((p: any) => p.id));

    // IDs not found in DB at all are unavailable
    const missingIds = ids.filter(id => !foundIds.has(id));

    // IDs found but inactive or out of stock
    const inactiveIds = (data ?? [])
        .filter((p: any) => !p.isActive)
        .map((p: any) => p.id);

    const unavailableIds = [...missingIds, ...inactiveIds];

    return NextResponse.json({
        success: true,
        data: data ?? [],
        unavailableIds,
    });
}

import { NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';
import * as requestService from '@/lib/services/requestService';
import { apiHandler } from '@/lib/middleware/apiHandler';
import { AppError } from '@/lib/utils/AppError';

export const dynamic = 'force-dynamic';

// Schema for query parameters
const querySchema = z.object({
    page: z.string().optional(),
    limit: z.string().optional(),
    search: z.string().optional(),
    status: z.string().optional(),
});

// Schema for creating a request
const createSchema = z.object({
    name: z.string().min(1, 'Name is required'),
    email: z.string().email('Invalid email'),
    itemType: z.string().min(1, 'Item type is required'),
    description: z.string().min(1, 'Description is required'),
    phone: z.string().optional(),
    budget: z.string().optional(),
    deadline: z.string().optional(),
    images: z.array(z.string()).optional(),
});

export const GET = apiHandler(async (req: NextRequest) => {
    const { searchParams } = new URL(req.url);
    const query = querySchema.parse(Object.fromEntries(searchParams));

    const result = await requestService.getAll({
        page: query.page ? parseInt(query.page) : 1,
        limit: query.limit ? parseInt(query.limit) : 10,
        search: query.search,
        status: query.status,
    });

    return NextResponse.json({
        success: true,
        data: result.data,
        pagination: result.pagination,
    });
});

export const POST = apiHandler(async (req: NextRequest) => {
    const body = await req.json();
    const validatedData = createSchema.parse(body);

    const newRequest = await requestService.create(validatedData);

    return NextResponse.json({
        success: true,
        data: newRequest,
    }, { status: 201 });
});

/**
 * @route   PUT /api/requests
 * @desc    Update a custom request
 */
export const PUT = apiHandler(async (req: NextRequest) => {
    const { searchParams } = new URL(req.url);
    const id = searchParams.get('id');
    if (!id) return NextResponse.json({ success: false, message: 'Request ID required' }, { status: 400 });

    const body = await req.json();
    const customReq = await requestService.update(id, body);
    return NextResponse.json({ success: true, data: customReq });
});

/**
 * @route   DELETE /api/requests
 * @desc    Delete a custom request
 */
export const DELETE = apiHandler(async (req: NextRequest) => {
    const { searchParams } = new URL(req.url);
    const id = searchParams.get('id');
    if (!id) return NextResponse.json({ success: false, message: 'Request ID required' }, { status: 400 });

    await requestService.remove(id);
    return NextResponse.json({ success: true, message: 'Request deleted successfully' });
});

import { NextResponse } from 'next/server';
import { revalidatePath } from 'next/cache';
import { z } from 'zod';
import { supabase } from '@/lib/supabase';
import { auditLog } from '@/lib/services/auditService';

const reviewSchema = z.object({
    product_id: z.string().optional(),
    customer_name: z.string().min(1).optional(),
    customer_email: z.string().email().optional(),
    rating: z.number().int().min(1).max(5).optional(),
    comment: z.string().optional(),
    status: z.enum(['pending', 'approved', 'rejected']).optional(),
    is_featured: z.boolean().optional(),
}).passthrough();


export const dynamic = 'force-dynamic';

export async function GET() {
    const { data, error } = await supabase
        .from('reviews')
        .select('*, products(name)')
        .order('created_at', { ascending: false });

    if (error) {
        console.error('Reviews API Error:', JSON.stringify(error));
        if (error.message.includes('schema cache') || error.message.includes('does not exist') || error.message.includes('relation')) {
            return NextResponse.json({ success: true, data: [] });
        }
        return NextResponse.json({ success: false, message: error.message }, { status: 500 });
    }

    const mapped = (data || []).map((r: any) => ({
        ...r,
        product_name: r.products?.name || null,
        products: undefined
    }));

    return NextResponse.json({ success: true, data: mapped });
}

export async function POST(request: Request) {
    const body = await request.json();
    const result = reviewSchema.safeParse(body);
    if (!result.success) {
        return NextResponse.json({ success: false, message: 'Validation failed', errors: result.error.issues.map(i => ({ field: i.path.join('.'), message: i.message })) }, { status: 400 });
    }
    const { data, error } = await supabase.from('reviews').insert([result.data]).select().single();
    if (error) return NextResponse.json({ success: false, message: error.message }, { status: 500 });
    await auditLog('reviews', data.id, 'CREATE', { customer_name: { from: null, to: data.customer_name } });
    revalidatePath('/', 'layout');
    return NextResponse.json({ success: true, data });
}

export async function PUT(request: Request) {
    const { searchParams } = new URL(request.url);
    const id = searchParams.get('id');
    if (!id) return NextResponse.json({ success: false, message: 'ID required' }, { status: 400 });
    const body = await request.json();
    const updateResult = reviewSchema.safeParse(body);
    if (!updateResult.success) {
        return NextResponse.json({ success: false, message: 'Validation failed', errors: updateResult.error.issues.map(i => ({ field: i.path.join('.'), message: i.message })) }, { status: 400 });
    }
    const { data, error } = await supabase.from('reviews').update(updateResult.data).eq('id', id).select().single();
    if (error) return NextResponse.json({ success: false, message: error.message }, { status: 500 });
    await auditLog('reviews', data.id, 'UPDATE');
    revalidatePath('/', 'layout');
    return NextResponse.json({ success: true, data });
}

export async function DELETE(request: Request) {
    const { searchParams } = new URL(request.url);
    const id = searchParams.get('id');
    if (!id) return NextResponse.json({ success: false, message: 'ID required' }, { status: 400 });
    const { error } = await supabase.from('reviews').delete().eq('id', id);
    if (error) return NextResponse.json({ success: false, message: error.message }, { status: 500 });
    await auditLog('reviews', id, 'DELETE');
    revalidatePath('/', 'layout');
    return NextResponse.json({ success: true });
}

