/**
 * Update a product
 * @param {string} id - Product UUID
 * @param {Partial<Product>} updates
 * @returns {Promise<Product>}
 */
export const update = async (id: string, updates: Partial<Product>) => {
    // Capture current state for audit diff
    const { data: before } = await supabase.from('products').select('*').eq('id', id).single();

    const { data, error } = await supabase
        .from('products')
        .update(updates)
        .eq('id', id)
        .select()
        .single();

    if (error) {
        throw new AppError(error.message, 500, 'DB_ERROR');
    }

    // Build field-level diff for audit
    if (before) {
        const changedFields: Record<string, { from: unknown; to: unknown }> = {};
        for (const key of Object.keys(updates) as (keyof Product)[]) {
            if (before[key] !== (data as any)[key]) {
                changedFields[key as string] = { from: before[key], to: (data as any)[key] };
            }
        }
        if (Object.keys(changedFields).length > 0) {
            await auditLog('products', id, 'UPDATE', changedFields);
        }
    }

    return data as Product;
};

/**
 * Delete a product
 * @param {string} id - Product UUID
 * @returns {Promise<void>}
 */
/**
 * Soft-delete a product (sets isActive = false).
 *
 * Strategy:
 *   - If the product has existing order_items → BLOCK deletion entirely.
 *     Order history is permanent business data and must not be destroyed.
 *     The admin should mark it inactive instead.
 *   - cart_items are ephemeral. The DB FK is set to ON DELETE CASCADE,
 *     so they are cleaned up automatically on a hard delete.
 *     On a soft delete we also clean them up explicitly so the cart
 *     doesn't show unavailable products to shoppers.
 *   - The product row itself is NOT removed from the DB; isActive = false
 *     hides it from the storefront while preserving order history references.
 *
 * @param {string} id - Product UUID
 * @returns {Promise<void>}
 */
export const remove = async (id: string) => {
    // 1. Guard: block if product is referenced in any order
    const { data: existingOrderItems, error: checkError } = await supabase
        .from('order_items')
        .select('id')
        .eq('product_id', id)
        .limit(1);

    if (checkError) {
        throw new AppError(checkError.message, 500, 'DB_ERROR');
    }

    if (existingOrderItems && existingOrderItems.length > 0) {
        throw new AppError(
            'This product has order history and cannot be permanently deleted. It has been archived (hidden from storefront) instead.',
            409,
            'CONFLICT'
        );
    }

    // 2. No orders → clean up cart_items (belt-and-suspenders; DB CASCADE also handles this)
    const { error: cartError } = await supabase
        .from('cart_items')
        .delete()
        .eq('product_id', id);

    if (cartError) {
        throw new AppError(cartError.message, 500, 'DB_ERROR');
    }

    // 3. Hard delete — safe because no orders reference this product
    const { error } = await supabase
        .from('products')
        .delete()
        .eq('id', id);

    if (error) {
        throw new AppError(error.message, 500, 'DB_ERROR');
    }

    await auditLog('products', id, 'DELETE');
};

/**
 * Soft-delete (archive) a product by setting isActive = false.
 * Use this when the product has order history and cannot be hard-deleted.
 *
 * Also removes any active cart_items for the product so shoppers
 * don't see unavailable items in their carts.
 *
 * @param {string} id - Product UUID
 * @returns {Promise<Product>} The updated (archived) product
 */
export const archive = async (id: string) => {
    // Clean up localStorage-based cart: the validate API will handle client side.
    // Also attempt DB cart_items cleanup if used.
    await supabase.from('cart_items').delete().eq('product_id', id);

    const { data, error } = await supabase
        .from('products')
        .update({ isActive: false, updatedAt: new Date().toISOString() })
        .eq('id', id)
        .select()
        .single();

    if (error) {
        throw new AppError(error.message, 500, 'DB_ERROR');
    }

    await auditLog('products', id, 'ARCHIVE', { isActive: { from: true, to: false } });
    return data as Product;
};

/**
 * Restore a previously archived product (sets isActive = true).
 *
 * @param {string} id - Product UUID
 * @returns {Promise<Product>} The restored product
 */
export const restore = async (id: string) => {
    const { data, error } = await supabase
        .from('products')
        .update({ isActive: true, updatedAt: new Date().toISOString() })
        .eq('id', id)
        .select()
        .single();

    if (error) {
        throw new AppError(error.message, 500, 'DB_ERROR');
    }

    await auditLog('products', id, 'RESTORE', { isActive: { from: false, to: true } });
    return data as Product;
};

import { supabase, type CustomRequest } from '@/lib/supabase';
import { AppError } from '@/lib/utils/AppError';
import { auditLog } from './auditService';

export type { CustomRequest };

export interface RequestStats {
    total: number;
    new: number;
    quoted: number;
    in_progress: number;
    completed: number;
}

// Map from UI/API-friendly values to actual DB enum values
const STATUS_MAP: Record<string, string> = {
    'new': 'NEW',
    'quoted': 'QUOTE_SENT',
    'quote_sent': 'QUOTE_SENT',
    'in_progress': 'IN_PROGRESS',
    'in-progress': 'IN_PROGRESS',
    'completed': 'COMPLETED',
    'cancelled': 'CANCELLED',
};

function toDbStatus(status: string): string {
    const lower = status.toLowerCase();
    return STATUS_MAP[lower] || status.toUpperCase();
}

/**
 * Get all requests with optional filtering
 */
export const getAll = async (query: {
    status?: string;
    search?: string;
    page?: number;
    limit?: number;
    includeArchived?: boolean;
}) => {
    let dbQuery = supabase
        .from('custom_requests')
        .select('*', { count: 'exact' });

    // Hide archived requests from normal admin views
    if (!query.includeArchived) {
        dbQuery = dbQuery.eq('isArchived', false);
    }

    if (query.search) {
        dbQuery = dbQuery.or(`name.ilike.%${query.search}%,email.ilike.%${query.search}%,itemType.ilike.%${query.search}%`);
    }

    dbQuery = dbQuery.order('createdAt', { ascending: false });

    const { data, error, count } = await dbQuery;

    if (error) throw new AppError(error.message, 500, 'DB_ERROR');

    let results = (data as CustomRequest[]) || [];

    // Client-side status filter
    if (query.status && query.status !== 'all') {
        results = results.filter(r => r.status?.toLowerCase() === query.status?.toLowerCase());
    }

    // Client-side pagination
    const page = query.page || 1;
    const limit = query.limit || 10;
    const from = (page - 1) * limit;
    const paginated = results.slice(from, from + limit);

    return {
        data: paginated,
        pagination: {
            total: results.length,
            page,
            limit,
            totalPages: Math.ceil(results.length / limit),
        },
    };
};

/**
 * Get request by ID
 */
export const getById = async (id: string) => {
    const { data, error } = await supabase
        .from('custom_requests')
        .select('*')
        .eq('id', id)
        .single();

    if (error) throw new AppError(error.message, 500, 'DB_ERROR');
    return data as CustomRequest;
};

/**
 * Create new request
 */
export const create = async (request: Omit<CustomRequest, 'id' | 'createdAt' | 'updatedAt' | 'status'>) => {
    const id = crypto.randomUUID();
    const now = new Date().toISOString();
    const { data, error } = await supabase
        .from('custom_requests')
        .insert([{ ...request, id, status: 'NEW', isArchived: false, createdAt: now, updatedAt: now }])
        .select()
        .single();

    if (error) throw new AppError(error.message, 500, 'DB_ERROR');

    await auditLog('custom_requests', id, 'CREATE', { status: { from: null, to: 'NEW' } });
    return data as CustomRequest;
};

/**
 * Update request status
 */
export const updateStatus = async (id: string, status: string) => {
    const dbStatus = toDbStatus(status);
    const { data: before } = await supabase.from('custom_requests').select('status').eq('id', id).single();

    const { data, error } = await supabase
        .from('custom_requests')
        .update({ status: dbStatus })
        .eq('id', id)
        .select()
        .single();

    if (error) throw new AppError(error.message, 500, 'DB_ERROR');

    await auditLog('custom_requests', id, 'UPDATE', {
        status: { from: before?.status ?? null, to: dbStatus },
    });
    return data as CustomRequest;
};

/**
 * Update request details
 */
export const update = async (id: string, updates: Partial<CustomRequest>) => {
    // Map status to DB enum value
    if (updates.status) {
        updates.status = toDbStatus(updates.status) as any;
    }

    // Strip read-only / auto-managed fields to avoid Supabase schema errors
    const { id: _id, createdAt: _createdAt, updatedAt: _updatedAt, ...safeUpdates } = updates as any;

    try {
        // Step 1: Perform the update (no .select() to avoid RLS RETURNING issues)
        const { error: updateError } = await supabase
            .from('custom_requests')
            .update(safeUpdates)
            .eq('id', id);

        if (updateError) {
            console.error('Supabase update error for CustomRequest:', JSON.stringify(updateError));
            throw new AppError(updateError.message, 500, 'DB_ERROR');
        }

        // Step 2: Re-fetch the updated record
        const { data, error: fetchError } = await supabase
            .from('custom_requests')
            .select('*')
            .eq('id', id)
            .single();

        if (fetchError) throw new AppError(fetchError.message, 500, 'DB_ERROR');
        return data as CustomRequest;
    } catch (err) {
        console.error('Failed to update request:', err);
        if (err instanceof AppError) throw err;
        throw new AppError(err instanceof Error ? err.message : 'Failed to update request', 500, 'DB_ERROR');
    }
};

/**
 * Soft-delete (archive) a request — sets isArchived = true.
 * Hard deletion is not allowed; requests are business records.
 */
export const remove = async (id: string) => {
    const { error } = await supabase
        .from('custom_requests')
        .update({ isArchived: true } as any)
        .eq('id', id);

    if (error) throw new AppError(error.message, 500, 'DB_ERROR');

    await auditLog('custom_requests', id, 'ARCHIVE', { isArchived: { from: false, to: true } });
    return { success: true };
};

/**
 * Restore an archived request — sets isArchived = false.
 */
export const restore = async (id: string) => {
    const { data, error } = await supabase
        .from('custom_requests')
        .update({ isArchived: false } as any)
        .eq('id', id)
        .select()
        .single();

    if (error) throw new AppError(error.message, 500, 'DB_ERROR');

    await auditLog('custom_requests', id, 'RESTORE', { isArchived: { from: true, to: false } });
    return data as CustomRequest;
};

/**
 * Get request statistics
 */
export const getStats = async (): Promise<RequestStats> => {
    const { data, error } = await supabase
        .from('custom_requests')
        .select('status');

    if (error) throw new AppError(error.message, 500, 'DB_ERROR');

    const stats = (data || []).reduce(
        (acc: RequestStats, curr) => {
            acc.total++;
            const status = curr.status?.toLowerCase() || 'new';
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            if ((acc as any)[status] !== undefined) {
                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                (acc as any)[status]++;
            }
            return acc;
        },
        { total: 0, new: 0, quoted: 0, in_progress: 0, completed: 0 }
    );

    return stats;
};
